var settingsSubscription = null;
var backgroundSyncLogger = serverLogger.child({ module: "background-sync" });
var MIN_BACKOFF_MS = 5000;
var MAX_BACKOFF_BASE_MS = 30000;
var MAX_BACKOFF_MS = 5 * 60000;
var syncQueue = new PQueue({ concurrency: 1 });
