// src/server/routes/remote.ts
function createRemoteRoutes() {
  const app = new Hono2;
  app.get("/ssh-hosts", async (c3) => c3.json(await getServerSshHosts()));
  app.post("/resolve-target", async (c3) => {
    const body = await c3.req.json().catch(() => null);
    const alias = typeof body?.alias === "string" ? body.alias : "";
    const remotePath = typeof body?.remotePath === "string" ? body.remotePath : "";
    return c3.json(await resolveServerRemoteTarget({ alias, remotePath }, c3.req.raw.signal));
  });
  app.post("/path-suggestions", async (c3) => {
    const body = await c3.req.json().catch(() => null);
    const alias = typeof body?.alias === "string" ? body.alias : "";
    const remotePath = typeof body?.remotePath === "string" ? body.remotePath : "";
    const prefix = typeof body?.prefix === "string" ? body.prefix : "";
    return c3.json(await getServerRemotePathSuggestions({ alias, remotePath, prefix }, c3.req.raw.signal));
  });
  app.post("/test-repository", async (c3) => {
    const body = await c3.req.json().catch(() => null);
    const target = normalizeRemoteTarget(body?.target);
    return c3.json(await testServerRemoteRepository(target ?? body?.target, c3.req.raw.signal));
  });
  app.post("/open-editor", async (c3) => {
    const body = await c3.req.json().catch(() => null);
    const repoId = typeof body?.repoId === "string" ? body.repoId : "";
    const worktreePath = typeof body?.worktreePath === "string" ? body.worktreePath : "";
    return c3.json(await openServerRemoteEditor({ repoId, worktreePath }, c3.req.raw.signal));
  });
  app.post("/open-terminal", async (c3) => {
    const body = await c3.req.json().catch(() => null);
    const repoId = typeof body?.repoId === "string" ? body.repoId : "";
    const worktreePath = typeof body?.worktreePath === "string" ? body.worktreePath : "";
    return c3.json(await openServerRemoteTerminal({ repoId, worktreePath }, c3.req.raw.signal));
  });
  return app;
}

// src/server/routes/realtime.ts
function createRealtimeRoutes({ internalSecret, terminalHost }) {
  const app = new Hono2;
  app.use("/invalidation", async (c3, next) => {
    if (c3.req.query("token") !== internalSecret)
      return c3.json({ ok: false, message: "Unauthorized" }, 401);
    await next();
  });
  app.use("/terminal", async (c3, next) => {
    if (c3.req.query("token") !== internalSecret)
      return c3.json({ ok: false, message: "Unauthorized" }, 401);
    if (!terminalHost.isValidClientId(c3.req.query("clientId")))
      return c3.json({ ok: false, message: "Invalid client id" }, 400);
    if (!c3.req.query("attachmentId"))
      return c3.json({ ok: false, message: "Missing attachment id" }, 400);
    await next();
  });
  app.get("/invalidation", upgradeWebSocket(() => {
    return {
      onOpen(_event, ws) {
        registerInvalidationSocket(ws);
      },
      onClose(_event, ws) {
        unregisterInvalidationSocket(ws);
      },
      onError(_event, ws) {
        unregisterInvalidationSocket(ws);
      }
    };
  }));
  app.get("/terminal", upgradeWebSocket((c3) => {
    const clientId = c3.req.query("clientId") ?? "";
    const attachmentId = c3.req.query("attachmentId") ?? "";
    return {
      onOpen(_event, ws) {
        terminalHost.registerSocket(clientId, attachmentId, ws);
      },
      onMessage(event, ws) {
        if (typeof event.data === "string") {
          terminalHost.handleRealtimeMessage(clientId, attachmentId, ws, event.data);
        }
      },
      onClose(_event, ws) {
        terminalHost.unregisterSocket(clientId, attachmentId, ws);
      },
      onError(_event, ws) {
        terminalHost.unregisterSocket(clientId, attachmentId, ws);
      }
    };
  }));
  return app;
}

