function isCommitMessageProvider(value) {
  return value === "codex" || value === "claude";
}

// src/server/modules/repo-read-paths.ts
async function probeRepository(cwd) {
  return await runWithRepoBackend(cwd, async (backend) => await backend.probe());
}
async function getRepositorySnapshot(cwd, signal) {
  return signal?.aborted ? null : await runWithRepoBackend(cwd, async (backend) => await backend.getSnapshot(signal));
}
async function getRepositoryStatus(cwd, signal) {
  return signal?.aborted ? [] : await runWithRepoBackend(cwd, async (backend) => await backend.getStatus(signal));
}
async function getRepositoryPullRequests(cwd, branches, options) {
  if (branches !== undefined && !Array.isArray(branches))
    return null;
  const mode = options?.mode === "summary" ? "summary" : "full";
  const branchSet = branches === undefined ? undefined : new Set(branches.filter((branch) => {
    return typeof branch === "string" && branch.length > 0;
  }));
  if (branchSet?.size === 0)
    return [];
  const branchNames = branchSet ? Array.from(branchSet) : undefined;
  const prs = await runWithRepoBackend(cwd, async (backend) => await backend.getPullRequests(branchNames, { mode, signal: options?.signal }));
  if (!prs)
    return null;
  return prs;
}
async function getRepositoryPatch(cwd, worktreePath, signal) {
  return await runWithRepoBackend(cwd, async (backend) => await backend.getPatch(worktreePath, signal));
}
async function getCommitMessageProviders(signal) {
  return await probeCommitMessageProviders(signal);
}
async function generateRepositoryCommitMessage(cwd, worktreePath, provider, signal) {
  if (!isCommitMessageProvider(provider))
    return { ok: false, message: "error.commit-message-provider-unavailable" };
  return await runWithRepoBackend(cwd, async (backend) => {
    const patch = await backend.getPatch(worktreePath, signal);
    if (!patch.ok)
      return patch;
    const generationCwd = backend.kind === "local" ? worktreePath : undefined;
    return await generateCommitMessageFromPatch(provider, patch.message, { cwd: generationCwd, signal });
  });
}
async function getRepositoryFileTree2(repoId, worktreePath, dirPath, signal) {
  return signal?.aborted ? { ok: false, message: "cancelled" } : await getRepositoryFileTree(repoId, worktreePath, dirPath, signal);
}

