// src/system/external-apps.ts
var lastDetectedAt = 0;
function nextDetectedAt(now = Date.now()) {
  const detectedAt = Math.max(now, lastDetectedAt + 1);
  lastDetectedAt = detectedAt;
  return detectedAt;
}
async function probeTerminalApps(pref, signal, detectedAt = nextDetectedAt()) {
  const appAvailability = await getTerminalAppAvailability(signal);
  const resolved = resolveTerminalApp(pref, appAvailability);
  return {
    pref,
    resolved,
    available: resolved !== null,
    appAvailability,
    detectedAt
  };
}
function probeEditorApps(pref, detectedAt = nextDetectedAt()) {
  const appAvailability = getEditorAppAvailability();
  const resolved = resolveEditorApp(pref, appAvailability);
  return {
    pref,
    resolved,
    available: resolved !== null,
    appAvailability,
    detectedAt
  };
}
async function probeExternalApps(terminalPref, editorPref, signal) {
  const detectedAt = nextDetectedAt();
  const terminals = await probeTerminalApps(terminalPref, signal, detectedAt);
  const editors = probeEditorApps(editorPref, detectedAt);
  return {
    terminals,
    editors
  };
}

// src/server/modules/external-apps.ts
async function buildServerExternalAppsSnapshot(settings, signal) {
  const state2 = await probeExternalApps(settings.terminalApp, settings.editorApp, signal);
  return { terminal: state2.terminals, editor: state2.editors };
}
async function getServerExternalAppsSnapshot(signal) {
  return await buildServerExternalAppsSnapshot(await getServerSettingsPrefs(), signal);
}

// src/server/modules/github-cli.ts
async function getServerGitHubCliState(signal, hosts, options) {
  return await probeGitHubCli(signal, hosts, options);
}

